import React from 'react';

function PlayButton({ isPlaying, togglePlay, updateMetadata }) {
  const handlePlayClick = async () => {
    togglePlay(); // Toggle the play state first

    if (!isPlaying) {
      try {
        const response = await fetch('https://your-azuracast-api-endpoint');
        if (response.ok) {
          const data = await response.json();
          // Assuming your AzuraCast API provides stream information as "streamData"
          updateMetadata(data.streamData || 'Unknown Stream');
        } else {
          console.error('Failed to fetch stream data from AzuraCast API');
          // Handle the error as needed
        }
      } catch (error) {
        console.error('Error fetching stream data:', error);
        // Handle the error as needed
      }
    }
  };

  return (
    <button className="play-button" onClick={handlePlayClick}>
      {isPlaying ? '❚❚' : '▶'}
    </button>
  );
}

export default PlayButton;
